pub async fn get_user_status(pool: &sqlx::PgPool) -> Result<Vec<GetUserStatusRow>, sqlx::Error> {
    sqlx::query_as!(GetUserStatusRow, "SELECT id, status AS \"status: UserStatus\" FROM users")
        .fetch_all(pool)
        .await
}

